#include "drv8825.h"
#include <Arduino.h>
#define STEP_P 25
#define DIR_P 26
#define EN_P 27
#define M0_P 12
#define M1_P 14
#define M2_P 13
static int _stepsLeft=0;static bool _cw=true;static unsigned long _lastStep=0;static unsigned long _stepDelay=500;
void drv8825_setup(){pinMode(STEP_P,OUTPUT);pinMode(DIR_P,OUTPUT);pinMode(EN_P,OUTPUT);pinMode(M0_P,OUTPUT);pinMode(M1_P,OUTPUT);pinMode(M2_P,OUTPUT);digitalWrite(EN_P,LOW);Serial.println("[drv8825] OK");}
void drv8825_move(int s,bool cw){_stepsLeft=abs(s);_cw=cw;digitalWrite(DIR_P,cw?HIGH:LOW);while(_stepsLeft>0){digitalWrite(STEP_P,HIGH);delayMicroseconds(2);digitalWrite(STEP_P,LOW);delayMicroseconds(_stepDelay);_stepsLeft--;}}
void drv8825_set_microstep(uint8_t m){digitalWrite(M0_P,m&1);digitalWrite(M1_P,(m>>1)&1);digitalWrite(M2_P,(m>>2)&1);}
void drv8825_enable(bool e){digitalWrite(EN_P,e?LOW:HIGH);}
